void main();

// entry.S needs one stack per CPU.
__attribute__((aligned(16))) char stack0[4096 * NCPU];

// entry.S jumps here in supervisor mode on stack0.
// a0 contains the hartid from OpenSBI
void start(unsigned long hartid) {
    // 通过OpenSBI的控制台功能输出，每个hart只输出一次
    SBI_PUTCHAR('H');
    SBI_PUTCHAR('e');
    SBI_PUTCHAR('l');
    SBI_PUTCHAR('l');
    SBI_PUTCHAR('o');
    SBI_PUTCHAR(' ');
    SBI_PUTCHAR('O');
    SBI_PUTCHAR('p');
    SBI_PUTCHAR('e');
    SBI_PUTCHAR('n');
    SBI_PUTCHAR('S');
    SBI_PUTCHAR('B');
    SBI_PUTCHAR('I');
    SBI_PUTCHAR(' ');
    SBI_PUTCHAR('h');
    SBI_PUTCHAR('a');
    SBI_PUTCHAR('r');
    SBI_PUTCHAR('t');
    SBI_PUTCHAR('i');
    SBI_PUTCHAR('d');
    SBI_PUTCHAR('=');
    // 输出hartid十进制值
    if (hartid == 0) {
        SBI_PUTCHAR('0');
    } else {
        // 简单实现十进制输出
        char digits[20];
        int idx = 0;
        unsigned long val = hartid;
        while (val > 0) {
            digits[idx++] = '0' + (val % 10);
            val /= 10;
        }
        while (idx > 0) {
            SBI_PUTCHAR(digits[--idx]);
        }
    }
    SBI_PUTCHAR('\r');
    SBI_PUTCHAR('\n');

    // Supervisor: disable paging for now.
    w_satp(0);

    // enable some supervisor interrupt
    w_sie(r_sie() | SIE_SEIE | SIE_STIE);

    // save hartid passed from OpenSBI
    w_tp(hartid);

    // enable supervisor mode deref user pointers.
    w_sstatus(r_sstatus() | SSTATUS_SUM);

    main();
}

#pragma once

#include "fs/vfs/file.h"
#include "time.h"

#define S_ISUID 04000  // set-user-ID bit
#define S_ISGID 02000  // set-group-ID bit

// Saved registers for kernel context switches.
#ifdef RISCV
struct context {
    uint64 ra;
    uint64 sp;

    // callee-saved
    uint64 s0;
    uint64 s1;
    uint64 s2;
    uint64 s3;
    uint64 s4;
    uint64 s5;
    uint64 s6;
    uint64 s7;
    uint64 s8;
    uint64 s9;
    uint64 s10;
    uint64 s11;
};
#elif defined(LOONGARCH)
struct context {
    uint64 ra;
    uint64 sp;

    // callee-saved
    uint64 s0;
    uint64 s1;
    uint64 s2;
    uint64 s3;
    uint64 s4;
    uint64 s5;
    uint64 s6;
    uint64 s7;
    uint64 s8;
    uint64 fp;
};
#endif

// Per-CPU state.
struct cpu {
    struct proc *proc;       // The process running on this cpu, or null.
    struct context context;  // swtch() here to enter scheduler().
    int noff;                // Depth of push_off() nesting.
    int intena;              // Were interrupts enabled before push_off()?
};

extern struct cpu cpus[NCPU];

// per-process data for the trap handling code in trampoline.S.
// sits in a page by itself just under the trampoline page in the
// user page table. not specially mapped in the kernel page table.
// uservec in trampoline.S saves user registers in the trapframe,
// then initializes registers from the trapframe's
// kernel_sp, kernel_hartid, kernel_satp, and jumps to kernel_trap.
// usertrapret() and userret in trampoline.S set up
// the trapframe's kernel_*, restore user registers from the
// trapframe, switch to the user page table, and enter user space.
// the trapframe includes callee-saved user registers like s0-s11 because the
// return-to-user path via usertrapret() doesn't return through
// the entire kernel call stack.
#ifdef RISCV
struct trapframe {
    /*   0 */ uint64 kernel_satp;    // kernel page table
    /*   8 */ uint64 kernel_sp;      // top of process's kernel stack
    /*  16 */ uint64 kernel_trap;    // usertrap()
    /*  24 */ uint64 epc;            // saved user program counter
    /*  32 */ uint64 kernel_hartid;  // saved kernel tp
    /*  40 */ uint64 ra;
    /*  48 */ uint64 sp;
    /*  56 */ uint64 gp;
    /*  64 */ uint64 tp;
    /*  72 */ uint64 t0;
    /*  80 */ uint64 t1;
    /*  88 */ uint64 t2;
    /*  96 */ uint64 s0;
    /* 104 */ uint64 s1;
    /* 112 */ uint64 a0;
    /* 120 */ uint64 a1;
    /* 128 */ uint64 a2;
    /* 136 */ uint64 a3;
    /* 144 */ uint64 a4;
    /* 152 */ uint64 a5;
    /* 160 */ uint64 a6;
    /* 168 */ uint64 a7;
    /* 176 */ uint64 s2;
    /* 184 */ uint64 s3;
    /* 192 */ uint64 s4;
    /* 200 */ uint64 s5;
    /* 208 */ uint64 s6;
    /* 216 */ uint64 s7;
    /* 224 */ uint64 s8;
    /* 232 */ uint64 s9;
    /* 240 */ uint64 s10;
    /* 248 */ uint64 s11;
    /* 256 */ uint64 t3;
    /* 264 */ uint64 t4;
    /* 272 */ uint64 t5;
    /* 280 */ uint64 t6;
};
#elif defined(LOONGARCH)
struct trapframe {
    /*   0 */ uint64 ra;
    /*   8 */ uint64 tp;
    /*  16 */ uint64 sp;
    /*  24 */ uint64 a0;
    /*  32 */ uint64 a1;
    /*  40 */ uint64 a2;
    /*  48 */ uint64 a3;
    /*  56 */ uint64 a4;
    /*  64 */ uint64 a5;
    /*  72 */ uint64 a6;
    /*  80 */ uint64 a7;
    /*  88 */ uint64 t0;
    /*  96 */ uint64 t1;
    /* 104 */ uint64 t2;
    /* 112 */ uint64 t3;
    /* 120 */ uint64 t4;
    /* 128 */ uint64 t5;
    /* 136 */ uint64 t6;
    /* 144 */ uint64 t7;
    /* 152 */ uint64 t8;
    /* 160 */ uint64 r21;
    /* 168 */ uint64 fp;
    /* 176 */ uint64 s0;
    /* 184 */ uint64 s1;
    /* 192 */ uint64 s2;
    /* 200 */ uint64 s3;
    /* 208 */ uint64 s4;
    /* 216 */ uint64 s5;
    /* 224 */ uint64 s6;
    /* 232 */ uint64 s7;
    /* 240 */ uint64 s8;
    /* 248 */ uint64 kernel_sp;      // top of process's kernel stack
    /* 256 */ uint64 kernel_trap;    // usertrap()
    /* 264 */ uint64 era;            // saved user program counter
    /* 272 */ uint64 kernel_hartid;  // saved kernel tp
    /* 280 */ uint64 kernel_pgdl;    // saved kernel pagetable
};
#endif

struct sysinfo {
    uint64 uptime;   // System uptime
    uint64 freeram;  // Free memory
    uint64 procs;    // Number of processes
};

#include "signal.h"

enum procstate { UNUSED, USED, SLEEPING, RUNNABLE, RUNNING, ZOMBIE };

// Virtual Memory Area for mmap
struct vma {
    uint64 addr;     // start address
    uint64 length;   // length in bytes
    int prot;        // protection flags
    int flags;       // mmap flags
    struct file *f;  // mapped file (NULL for anonymous)
    uint64 offset;   // offset in file
    int valid;       // 1 if this VMA is valid, 0 if free
};

// Per-process state
struct proc {
    struct spinlock lock;

    // p->lock must be held when using these:
    enum procstate state;  // Process state
    void *chan;            // If non-zero, sleeping on chan
    int killed;            // If non-zero, have been killed
    int xstate;            // Exit status to be returned to parent's wait
    int pid;               // Process ID 
    int tgid;              // Thread group ID
    int tid;               // Thread ID

    // wait_lock must be held when using this:
    struct proc *parent;  // Parent process

    // these are private to the process, so p->lock need not be held.
    uint64 kstack;                // Virtual address of kernel stack
    uint64 sz;                    // Size of process memory (bytes)
    pagetable_t pagetable;        // User page table
    struct trapframe *trapframe;  // data page for trampoline.S
    struct context context;       // swtch() here to run process
    struct file *ofile[NOFILE];   // Open files
    struct file_vnode cwd;        // Current directory
    char exec_path[MAXPATH];     // Executable path (for /proc/self/exe)
    char name[16];                // Process name (debugging)
    char console_buf[256];        // Per-process console write buffer
    int console_buf_pos;          // Position in console_buf
    struct vma vmas[NVMA];        // Virtual Memory Areas for mmap
    uint64 clear_child_tid;       // Clear child tid
    uint64 robust_list_head;      // Robust futex list head
    int pt_shared;                // Page table shared via CLONE_VM
    int uid;                      // Real user ID
    int euid;                     // Effective user ID
    int suid;                     // Saved set-user-ID
    int gid;                      // Real group ID
    int egid;                     // Effective group ID
    int sgid;                     // Saved set-group-ID

    // Signal related
    sigset_t sig_blocked;               // Signal mask
    uint64 sig_pending;                 // Pending signal bitmap
    struct sig_handlers *sig_handlers;  // Signal handler table
    struct sig_context *sig_context;    // Signal handling context stack
};

#include "types.h"
#include "param.h"
#include "memlayout.h"
#include "platform.h"
#include "lock/lock.h"
#include "proc/proc.h"

#include "fs/vfs/fs.h"

#include "defs.h"
#include "mem.h"
#include "errno.h"

struct cpu cpus[NCPU];

struct proc proc[NPROC];

struct proc *initproc;

int nextpid = 1;
struct spinlock pid_lock;

extern void forkret(void);
static void freeproc(struct proc *p);

extern char trampoline[];  // trampoline.S
extern char sig_trampoline[];

// helps ensure that wakeups of wait()ing
// parents are not lost. helps obey the
// memory model when using p->parent.
// must be acquired before any p->lock.
struct spinlock wait_lock;

// Allocate a page for each process's kernel stack.
// Map it high in memory, followed by an invalid
// guard page.
void proc_mapstacks(pagetable_t kpgtbl) {
    struct proc *p;
#ifdef RISCV
    for (p = proc; p < &proc[NPROC]; p++) {
        char *pa = kmalloc(4 * PGSIZE);
        if (pa == 0) panic("kalloc");
        uint64 va = KSTACK((int)(p - proc));
        kvmmap(kpgtbl, va, (uint64)pa, 4 * PGSIZE, PTE_R | PTE_W);
    }
#elif defined(LOONGARCH)

    for (p = proc; p < &proc[NPROC]; p++) {
        char *pa = kalloc();
        if (pa == 0) panic("kalloc");
        uint64 va = KSTACK((int)(p - proc));
#ifdef LA2K1000
        if (mappages(kpgtbl, va, PGSIZE, (uint64)pa, PTE_P | PTE_W | PTE_MAT | PTE_D) != 0)
#else
        if (mappages(kpgtbl, va, PGSIZE, (uint64)pa, PTE_NX | PTE_P | PTE_W | PTE_MAT | PTE_D) != 0)
#endif
            panic("kvmmap");
    }
#endif
}

// initialize the proc table.
void procinit(void) {
    struct proc *p;
    struct cpu *c;

    // 显式初始化CPU数组，确保noff等字段为0
    for (c = cpus; c < &cpus[NCPU]; c++) {
        c->noff = 0;
        c->intena = 0;
        c->proc = 0;
    }

    initlock(&pid_lock, "nextpid");
    initlock(&wait_lock, "wait_lock");
    for (p = proc; p < &proc[NPROC]; p++) {
        initlock(&p->lock, "proc");
        p->state = UNUSED;
        p->kstack = KSTACK((int)(p - proc));
    }
}

// Must be called with interrupts disabled,
// to prevent race with process being moved
// to a different CPU.
int cpuid() {
    int id = r_tp();
    return id;
}

// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu *mycpu(void) {
    int id = cpuid();
    struct cpu *c = &cpus[id];
    return c;
}

// Return the current struct proc *, or zero if none.
struct proc *myproc(void) {
    push_off();
    struct cpu *c = mycpu();
    struct proc *p = c->proc;
    pop_off();
    return p;
}

int allocpid() {
    int pid;

    acquire(&pid_lock);
    pid = nextpid;
    nextpid = nextpid + 1;
    release(&pid_lock);

    return pid;
}

// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel,
// and return with p->lock held.
// If there are no free procs, or a memory allocation fails, return 0.
static struct proc *allocproc(void) {
    struct proc *p;

    for (p = proc; p < &proc[NPROC]; p++) {
        acquire(&p->lock);
        if (p->state == UNUSED) {
            goto found;
        } else {
            release(&p->lock);
        }
    }
    return 0;

found:
    p->pid = allocpid();
    p->tgid = p->pid; // Default: tgid == pid (single-threaded process)
    p->tid = p->pid;  // Default: tid == pid
    p->state = USED;
    p->clear_child_tid = 0;
    p->robust_list_head = 0;
    p->pt_shared = 0;
    p->uid = 0;
    p->euid = 0;
    p->suid = 0;
    p->gid = 0;
    p->egid = 0;
    p->sgid = 0;
    p->killed = 0;  // ensure known initial state
    p->exec_path[0] = '\0';
    p->console_buf_pos = 0;
    memset(p->console_buf, 0, sizeof(p->console_buf));
    for (int i = 0; i < NOFILE; i++) {
        p->ofile[i] = 0;
    }

    // signal init
    sig_init(p);

    // Allocate a trapframe page.
    if ((p->trapframe = (struct trapframe *)kalloc()) == 0) {
        freeproc(p);
        release(&p->lock);
        return 0;
    }
#ifdef LA2K1000
    // 避免第一次 userret 从未初始化的陷阱帧恢复出随机寄存器/era
    memset(p->trapframe, 0, PGSIZE);
#endif

    // An empty user page table.
    p->pagetable = proc_pagetable(p);
    if (p->pagetable == 0) {
        freeproc(p);
        release(&p->lock);
        return 0;
    }

    // Set up new context to start executing at forkret,
    // which returns to user space.
    memset(&p->context, 0, sizeof(p->context));
    p->context.ra = (uint64)forkret;
    p->context.sp = p->kstack + PGSIZE;

    // Initialize VMA array
    memset(&p->vmas, 0, NVMA * sizeof(struct vma));

    return p;
}

// free a proc structure and the data hanging from it,
// including user pages.
// p->lock must be held.
static void freeproc(struct proc *p) {
    if (p->trapframe) kfree((void *)p->trapframe);
    p->trapframe = 0;

    // Clean up VMA mappings
    if (!p->pt_shared) {
        for (int i = 0; i < NVMA; i++) {
            struct vma *v = &p->vmas[i];
            if (v->valid) {
                vmaunmap(p->pagetable, v->addr, v->length, v);
                if (v->f) {
                    get_fops()->close(v->f);
                }
                v->valid = 0;
            }
        }
    }

    sig_cleanup(p);

    // flush any buffered console output (last line may not end with \n)
    console_flush(p);

    if (p->pagetable && !p->pt_shared)
        proc_freepagetable(p->pagetable, p->sz);
    p->pagetable = 0;
    p->sz = 0;
    p->pid = 0;
    p->parent = 0;
    p->name[0] = 0;
    p->chan = 0;
    p->killed = 0;
    p->xstate = 0;
    p->state = UNUSED;
}

// Create a user page table for a given process, with no user memory,
// but with trampoline and trapframe pages.
pagetable_t proc_pagetable(struct proc *p) {
    pagetable_t pagetable;

    // An empty page table.
    pagetable = uvmcreate();
    if (pagetable == 0) return 0;
#ifdef RISCV
    // map the trampoline code (for system call return)
    // at the highest user virtual address.
    // only the supervisor uses it, on the way
    // to/from user space, so not PTE_U.
    if (mappages(pagetable, TRAMPOLINE, PGSIZE, (uint64)trampoline, PTE_R | PTE_X) < 0) {
        uvmfree(pagetable, 0);
        return 0;
    }

    if (mappages(pagetable, SIG_TRAMPOLINE, PGSIZE, (uint64)sig_trampoline, PTE_R | PTE_X | PTE_U) <
        0) {
        uvmunmap(pagetable, TRAMPOLINE, 1, 0);
        uvmfree(pagetable, 0);
        return 0;
    }

    // map the trapframe page just below the trampoline page, for
    // trampoline.S.
    if (mappages(pagetable, TRAPFRAME, PGSIZE, (uint64)(p->trapframe), PTE_R | PTE_W) < 0) {
        uvmunmap(pagetable, TRAMPOLINE, 1, 0);
        uvmunmap(pagetable, SIG_TRAMPOLINE, 1, 0);
        uvmfree(pagetable, 0);
        return 0;
    }
#elif defined(LOONGARCH)
#ifdef LA2K1000
    if (mappages(pagetable, TRAPFRAME, PGSIZE, (uint64)(p->trapframe),
                 PTE_P | PTE_W | PTE_MAT | PTE_D | PTE_U) < 0) {
#else
    if (mappages(pagetable, TRAPFRAME, PGSIZE, (uint64)(p->trapframe),
                 PTE_NX | PTE_P | PTE_W | PTE_MAT | PTE_D) < 0) {
#endif
        uvmfree(pagetable, 0);
        return 0;
    }

    if (mappages(pagetable, SIG_TRAMPOLINE, PGSIZE, (uint64)sig_trampoline,
                 PTE_P | PTE_MAT | PTE_D | PTE_U) < 0) {
        printf("Fail to map sig_trampoline\n");
        uvmunmap(pagetable, TRAPFRAME, 1, 0);
        uvmfree(pagetable, 0);
