int filestat(struct file *f, uint64 addr) {
    struct proc *p = myproc();
    struct kstat st;
    // Special system files without ext4 backing
    if (f->f_extfile == NULL) {
        memset(&st, 0, sizeof(st));
        st.st_dev = 0;
        st.st_ino = 1;
        st.st_mode = 0x81A4;  // S_IFREG | 0644
        st.st_nlink = 1;
        st.st_uid = 0;
        st.st_gid = 0;
        st.st_rdev = 0;
        st.st_size = 0;
        st.st_blksize = 4096;
        st.st_blocks = 1;
        st.st_atime_sec = 0;
        st.st_ctime_sec = 0;
        st.st_mtime_sec = 0;
        if (copyout(p->pagetable, addr, (char *)(&st), sizeof(st)) < 0) return -1;
        return 0;
    }
    // Use path-based stat so it works for both files and directories
    if (vfs_ext_stat(f->f_path, &st) < 0) {
        return -1;
    }
    if (copyout(p->pagetable, addr, (char *)(&st), sizeof(st)) < 0) return -1;
    return 0;
}

