        strcat(absolute_path, path);
    }
    // handle ./ and ../
    char *p = absolute_path;
    while (*p != '\0') {
        if (*p == '.' && *(p + 1) != '\0' && *(p + 1) == '/') {
            strcpy(p, p + 2);
        } else if (*p == '.' && *(p + 1) != '\0' && *(p + 1) == '.' && *(p + 2) != '\0' &&
