    // Allocate stack at fixed high address
    if ((sz1 = uvmalloc(pagetable, USTACK, USTACK_TOP, PTE_W | PTE_R | PTE_U)) == 0) goto bad;
    uvmclear(pagetable, USTACK);  // Guard page

    sp = USTACK_TOP;
    stackbase = USTACK;
    sp -= sizeof(uint64);

    for (envc = 0; envp[envc]; envc++) {
        if (envc >= MAXENV) {
            goto bad;
