    AUXV(AT_PAGESZ, PGSIZE);
    AUXV(AT_PHDR, first_load_vaddr + elf.phoff);
    AUXV(AT_PHENT, elf.phentsize);
    AUXV(AT_PHNUM, elf.phnum);
    AUXV(AT_BASE, 0);
    AUXV(AT_ENTRY, elf.entry);
