    AUXV(AT_EUID, has_setuid ? file_uid : p->euid);
    AUXV(AT_GID, p->gid);
    AUXV(AT_EGID, has_setgid ? file_gid : p->egid);
    AUXV(AT_SECURE, (has_setuid || has_setgid) ? 1 : 0);
    AUXV(AT_RANDOM, sp);
    AUXV(AT_NULL, 0);

