        char byte_to_write = ((char *)addr)[bytes_written];
        pi->data[pi->nwrite++ % PIPESIZE] = byte_to_write;
        bytes_written++;
    }

    // Wake up any waiting readers
    wakeup(&pi->nread);
    release(&pi->lock);

    return bytes_written;
}

