#endif

struct {
    struct spinlock lock;
    struct buf buf[NBUF];

    // Linked list of all buffers, through prev/next.
    // Sorted by how recently the buffer was used.
    // head.next is most recent, head.prev is least.
    struct buf head;
} bcache;

void binit(void) {
    struct buf *b;

    initlock(&bcache.lock, "bcache");

    // Create linked list of buffers
    bcache.head.prev = &bcache.head;
    bcache.head.next = &bcache.head;
    for (b = bcache.buf; b < bcache.buf + NBUF; b++) {
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        initsleeplock(&b->lock, "buffer");
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }
}

// Look through buffer cache for block on device dev.
// If not found, allocate a buffer.
// In either case, return locked buffer.
struct buf *bget(uint dev, uint blockno) {
    struct buf *b;

    acquire(&bcache.lock);

    // Is the block already cached?
    for (b = bcache.head.next; b != &bcache.head; b = b->next) {
        if (b->dev == dev && b->blockno == blockno) {
            b->refcnt++;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }

    // Not cached.
    // Recycle the least recently used (LRU) unused buffer.
    for (b = bcache.head.prev; b != &bcache.head; b = b->prev) {
        if (b->refcnt == 0) {
            b->dev = dev;
            b->blockno = blockno;
            b->valid = 0;
            b->refcnt = 1;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }
    panic("bget: no buffers");
}

// Return a locked buf with the contents of the indicated block.
struct buf *bread(uint dev, uint blockno) {
    struct buf *b;

    b = bget(dev, blockno);
    if (!b->valid) {
#if defined(VF2) || defined(LA2K1000)
        ramdisk_rw(b, 0);  // 0 = read
#else
        virtio_disk_rw(b, 0);
#endif
        b->valid = 1;
    }
    return b;
}

// Write b's contents to disk.  Must be locked.
void bwrite(struct buf *b) {
    if (!holdingsleep(&b->lock)) panic("bwrite");
#if defined(VF2) || defined(LA2K1000)
    ramdisk_rw(b, 1);  // 1 = write
#else
    virtio_disk_rw(b, 1);
#endif
}

// Release a locked buffer.
// Move to the head of the most-recently-used list.
void brelse(struct buf *b) {
    if (!holdingsleep(&b->lock)) panic("brelse");

    releasesleep(&b->lock);

    acquire(&bcache.lock);
    b->refcnt--;
    if (b->refcnt == 0) {
        // no one is waiting for it.
        b->next->prev = b->prev;
        b->prev->next = b->next;
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }

    release(&bcache.lock);
}

void bpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt++;
    release(&bcache.lock);
}

void bunpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt--;
    release(&bcache.lock);
}

//
// Console input and output, to the uart.
// Reads are line at a time.
// Implements special input characters:
//   newline -- end of line
//   control-h -- backspace
//   control-u -- kill line
//   control-d -- end of file
//   control-p -- print process list
//

#include <stdarg.h>

#include "types.h"
#include "param.h"
#include <lock/lock.h>
#include <fs/vfs/fs.h>
#include <fs/vfs/file.h>
#include "memlayout.h"
#include "platform.h"
#include "defs.h"
#include <proc/proc.h>
#include <lib/sbi.h>

#ifdef RISCV
#define PUTCHAR(c) SBI_PUTCHAR(c)
#elif defined(LOONGARCH)
#define PUTCHAR(c) uartputc_sync(c)
#endif

#define BACKSPACE 0x100
#define C(x) ((x) - '@')  // Control-x

struct {
    struct spinlock lock;
    struct spinlock write_lock;

    // input
#define INPUT_BUF_SIZE 128
    char buf[INPUT_BUF_SIZE];
    uint r;  // Read index
    uint w;  // Write index
    uint e;  // Edit index
} cons;

//
// send one character to the uart.
// called by printf(), and to echo input characters,
// but not from write().
//
void consputc(int c) {
    if (c == BACKSPACE) {
        // if the user typed backspace, overwrite with a space.
        PUTCHAR('\b');
        PUTCHAR(' ');
        PUTCHAR('\b');
    } else if (c == '\n' || c == '\r') {
        PUTCHAR('\n');
    } else {
        PUTCHAR(c);
    }
}

//
// user write()s to the console go here.
// Buffered per-process: output is accumulated until \n or buffer full,
// then flushed atomically to avoid interleaving under timer preemption.
//
int consolewrite(int user_src, uint64 src, int n) {
    int i;
    struct proc *p = myproc();

    for (i = 0; i < n; i++) {
        char c;
        if (either_copyin(&c, user_src, src + i, 1) == -1) break;

        if (p->console_buf_pos < (int)sizeof(p->console_buf) - 1)
            p->console_buf[p->console_buf_pos++] = c;

        if (c == '\n' || p->console_buf_pos >= (int)sizeof(p->console_buf) - 1) {
            acquire(&cons.write_lock);
            for (int j = 0; j < p->console_buf_pos; j++)
                PUTCHAR(p->console_buf[j]);
            release(&cons.write_lock);
            p->console_buf_pos = 0;
        }
    }
    return i;
}

//
// Flush any buffered console output for a process.
// Called on process exit to avoid losing the last line
// (which may not end with \n).
//
void console_flush(struct proc *p) {
    if (p->console_buf_pos > 0) {
        acquire(&cons.write_lock);
        for (int j = 0; j < p->console_buf_pos; j++)
            PUTCHAR(p->console_buf[j]);
        release(&cons.write_lock);
        p->console_buf_pos = 0;
    }
}

//
// user read()s from the console go here.
// copy (up to) a whole input line to dst.
// user_dist indicates whether dst is a user
// or kernel address.
//
int consoleread(int user_dst, uint64 dst, int n) {
    uint target;
    int c;
    char cbuf;

    target = n;
    acquire(&cons.lock);
    while (n > 0) {
        // wait until interrupt handler has put some
        // input into cons.buffer.
        while (cons.r == cons.w) {
            if (killed(myproc())) {
                release(&cons.lock);
                return -1;
            }
            sleep(&cons.r, &cons.lock);
        }

        c = cons.buf[cons.r++ % INPUT_BUF_SIZE];

        if (c == C('D')) {  // end-of-file
            if (n < target) {
                // Save ^D for next time, to make sure
                // caller gets a 0-byte result.
                cons.r--;
            }
            break;
        }

        // copy the input byte to the user-space buffer.
        cbuf = c;
        if (either_copyout(user_dst, dst, &cbuf, 1) == -1) break;

        dst++;
        --n;

        if (c == '\n') {
            // a whole line has arrived, return to
            // the user-level read().
            break;
        }
    }
    release(&cons.lock);

    return target - n;
}

//
// the console input interrupt handler.
// uartintr() calls this for input character.
// do erase/kill processing, append to cons.buf,
// wake up consoleread() if a whole line has arrived.
//
void consoleintr(int c) {
    acquire(&cons.lock);

    switch (c) {
        case C('P'):  // Print process list.
            procdump();
            break;
        case C('U'):  // Kill line.
            while (cons.e != cons.w && cons.buf[(cons.e - 1) % INPUT_BUF_SIZE] != '\n') {
                cons.e--;
                consputc(BACKSPACE);
            }
            break;
        case C('H'):  // Backspace
        case '\x7f':  // Delete key
            if (cons.e != cons.w) {
                cons.e--;
                consputc(BACKSPACE);
            }
            break;
        default:
            if (c != 0 && cons.e - cons.r < INPUT_BUF_SIZE) {
                c = (c == '\r') ? '\n' : c;

                // echo back to the user.
                consputc(c);

                // store for consumption by consoleread().
                cons.buf[cons.e++ % INPUT_BUF_SIZE] = c;

                if (c == '\n' || c == C('D') || cons.e - cons.r == INPUT_BUF_SIZE) {
                    // wake up consoleread() if a whole line (or end-of-file)
                    // has arrived.
                    cons.w = cons.e;
                    wakeup(&cons.r);
                }
            }
            break;
    }

    release(&cons.lock);
}

void consoleinit(void) {
    initlock(&cons.lock, "cons");
    initlock(&cons.write_lock, "cons_write");

    uartinit();

    // connect read and write system calls
    // to consoleread and consolewrite.
    devsw[CONSOLE].read = consoleread;
    devsw[CONSOLE].write = consolewrite;
}

#pragma once
// Physical memory layout

// qemu -machine virt is set up like this,
// based on qemu's hw/riscv/virt.c:
//
// 00001000 -- boot ROM, provided by qemu
// 02000000 -- CLINT
// 0C000000 -- PLIC
// 10000000 -- uart0
// 10001000 -- virtio disk
// 80000000 -- boot ROM jumps here in machine mode
//             -kernel loads the kernel here
// unused RAM after 80000000.

// the kernel uses physical memory thus:
// 80000000 -- entry.S, then kernel text and data
// end -- start of kernel page allocation area
// PHYSTOP -- end RAM used by the kernel

// qemu puts UART registers here in physical memory.

#ifdef VF2
// VisionFive2 board memory layout
#define UART0 0x10000000L
// On VF2, UART0 interrupt source ID is 32 on the PLIC
#define UART0_IRQ 32

// virtio mmio interface (same as QEMU virt machine)
#define VIRTIO0 0x10001000
// Keep virtio on standard source if present; adjust if board uses different ID
#define VIRTIO0_IRQ 1

#define CLOCK_IRQ 5

// core local interruptor (CLINT), which contains the timer.
#define CLINT 0x2000000L
#define CLINT_MTIMECMP(hartid) (CLINT + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT + 0xBFF8)

// Platform-level interrupt controller (PLIC)
#define PLIC 0x0c000000L
#define PLIC_PRIORITY (PLIC + 0x0)
#define PLIC_PENDING (PLIC + 0x1000)
// VF2 S-mode context windows (align with reference project layout)
#define PLIC_MENABLE(hart) (PLIC + 0x2000 + ((hart) - 1) * 0x100)
#define PLIC_SENABLE(hart) (PLIC + 0x2100 + ((hart) - 1) * 0x100)
#define PLIC_MPRIORITY(hart) (PLIC + 0x200000 + ((hart) - 1) * 0x2000)
#define PLIC_SPRIORITY(hart) (PLIC + 0x202000 + ((hart) - 1) * 0x2000)
#define PLIC_MCLAIM(hart) (PLIC + 0x200004 + ((hart) - 1) * 0x2000)
#define PLIC_SCLAIM(hart) (PLIC + 0x202004 + ((hart) - 1) * 0x2000)

// VF2 kernel base address (loaded by u-boot at 0x80400000)
#define KERNBASE 0x80400000
#define PHYSTOP 0x88000000

#define TRAMPOLINE (MAXVA - PGSIZE)
#define USTACK_PAGE 32
#define USTACK (MAXVA - 512 * 10 * PGSIZE - USTACK_PAGE * PGSIZE)
#define USTACK_GURAD_PAGE (USTACK - PGSIZE)
#define USTACK_TOP (USTACK + USTACK_PAGE * PGSIZE)
#define KSTACK(p) (TRAMPOLINE - ((p) + 1) * 4 * PGSIZE)
#define SIG_TRAMPOLINE (TRAMPOLINE - PGSIZE)
#define TRAPFRAME (SIG_TRAMPOLINE - PGSIZE)
#define MMAPEND TRAPFRAME

#elif defined(RISCV)

#define UART0 0x10000000L
#define UART0_IRQ 10

// virtio mmio interface
#define VIRTIO0 0x10001000
#define VIRTIO0_IRQ 1

#define CLOCK_IRQ 5

// core local interruptor (CLINT), which contains the timer.
#define CLINT 0x2000000L
#define CLINT_MTIMECMP(hartid) (CLINT + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT + 0xBFF8)  // cycles since boot.

// qemu puts platform-level interrupt controller (PLIC) here.
#define PLIC 0x0c000000L
#define PLIC_PRIORITY (PLIC + 0x0)
#define PLIC_PENDING (PLIC + 0x1000)
#define PLIC_MENABLE(hart) (PLIC + 0x2000 + (hart) * 0x100)
#define PLIC_SENABLE(hart) (PLIC + 0x2080 + (hart) * 0x100)
#define PLIC_MPRIORITY(hart) (PLIC + 0x200000 + (hart) * 0x2000)
#define PLIC_SPRIORITY(hart) (PLIC + 0x201000 + (hart) * 0x2000)
#define PLIC_MCLAIM(hart) (PLIC + 0x200004 + (hart) * 0x2000)
#define PLIC_SCLAIM(hart) (PLIC + 0x201004 + (hart) * 0x2000)

// the kernel expects there to be RAM
// for use by the kernel and user pages
// from physical address 0x80000000 to PHYSTOP.
#define KERNBASE 0x80000000
#define PHYSTOP 0x88000000

// map the trampoline page to the highest address,
// in both user and kernel space.
#define TRAMPOLINE (MAXVA - PGSIZE)

#define USTACK_PAGE 32
#define USTACK (MAXVA - 512 * 10 * PGSIZE - USTACK_PAGE * PGSIZE)
#define USTACK_GURAD_PAGE (USTACK - PGSIZE)
#define USTACK_TOP (USTACK + USTACK_PAGE * PGSIZE)
// map kernel stacks beneath the trampoline,
// each surrounded by invalid guard pages.
#define KSTACK(p) (TRAMPOLINE - ((p) + 1) * 4 * PGSIZE)

#define SIG_TRAMPOLINE (TRAMPOLINE - PGSIZE)

// User memory layout.
// Address zero first:
//   text
//   original data and bss
//   fixed-size stack
//   expandable heap
//   ...
//   TRAPFRAME (p->trapframe, used by the trampoline)
//   TRAMPOLINE (the same page as in the kernel)
#define TRAPFRAME (SIG_TRAMPOLINE - PGSIZE)

#define MMAPEND TRAPFRAME

#elif defined(LOONGARCH)
// Physical memory layout (LoongArch)

// LoongArch direct-map windows
#define DMWIN_MASK 0x9000000000000000
#define DMWIN1_MASK 0x8000000000000000
#define VIRT_DMWIN_MASK 0xf000000000000000

#define VIRT2PHY(addr) ((addr) & ~VIRT_DMWIN_MASK)

#ifdef LA2K1000
// ===================== 2K1000 板级映射（39位地址空间高位使用） =====================
#include "board/2k1000.h"

// UART 与中断编号（IOINTC 提供 UART0=2，定时器仍用 5）
// 早期阶段优先走 DMWIN1(0x8...) 非缓存直映，避免 0x9... 触发 TLB 异常
#define UART0 (LA2K1000_UART0_BASE | DMWIN1_MASK)
#define UART0_IRQ LA2K1000_UART0_IRQ
#define CLOCK_IRQ 5

// 物理内存直映区（教学 OS 约定）
#define PHYSBASE (0x90000000UL | DMWIN_MASK)
#define PHYSTOP (PHYSBASE + 512 * 1024 * 1024)

// 39位地址空间最大值 (2^39 - 1)
#define MAXVA_39BIT (1ULL << 39)

// 用户/内核栈与陷阱帧布局（2K1000：启用39位高位使用）
#define TRAPFRAME (MAXVA_39BIT - PGSIZE)     // 39位地址空间顶部下方一页
#define SIG_TRAMPOLINE (TRAPFRAME - PGSIZE)  // 信号跳板页

#define USTACK_PAGE 32
#define USTACK_TOP (SIG_TRAMPOLINE)                 // 栈顶紧贴信号跳板页下方
#define USTACK (USTACK_TOP - USTACK_PAGE * PGSIZE)  // 用户栈空间
#define USTACK_GURAD_PAGE (USTACK - PGSIZE)         // 栈保护页

#define MMAPEND (USTACK)  // mmap 空间位于栈之下

// 每进程内核栈（使用高位地址空间）
#define KSTACK(p) (TRAPFRAME - ((p) + 1) * 2 * PGSIZE)

// 便捷宏
#define PA2VA(pa) ((pa) & (~(DMWIN_MASK)))

#else

// ===================== LoongArch 默认（QEMU/LS7A） =====================

// qemu puts UART registers here in virtual memory.
#define UART0 (0x1fe001e0UL | DMWIN_MASK)
#define UART0_IRQ 2

#define CLOCK_IRQ 5

/* ============== LS7A registers =============== */
#define LS7A_PCH_REG_BASE (0x10000000UL | DMWIN_MASK)

#define LS7A_INT_MASK_REG LS7A_PCH_REG_BASE + 0x020
#define LS7A_INT_EDGE_REG LS7A_PCH_REG_BASE + 0x060
#define LS7A_INT_CLEAR_REG LS7A_PCH_REG_BASE + 0x080
#define LS7A_INT_HTMSI_VEC_REG LS7A_PCH_REG_BASE + 0x200
#define LS7A_INT_STATUS_REG LS7A_PCH_REG_BASE + 0x3a0
#define LS7A_INT_POL_REG LS7A_PCH_REG_BASE + 0x3e0

// the kernel expects there to be RAM for use by user pages from PHYSBASE to PHYSTOP
#define PHYSBASE (0x90000000UL | DMWIN_MASK)
#define PHYSTOP (PHYSBASE + 512 * 1024 * 1024)

#define USTACK_PAGE 32
#define USTACK (MAXVA - 512 * 10 * PGSIZE - USTACK_PAGE * PGSIZE)
#define USTACK_GURAD_PAGE (USTACK - PGSIZE)
#define USTACK_TOP (USTACK + USTACK_PAGE * PGSIZE)

// map kernel stacks beneath the trampframe, each surrounded by invalid guard pages.
#define KSTACK(p) (TRAPFRAME - ((p) + 1) * 2 * PGSIZE)

// User memory layout（见注释）
#define TRAPFRAME (MAXVA - PGSIZE)
#define SIG_TRAMPOLINE (TRAPFRAME - PGSIZE)

#define MMAPEND SIG_TRAMPOLINE

#define PA2VA(pa) ((pa) & (~(DMWIN_MASK)))

#endif  // LA2K1000

#endif

